301	  label: string;
302	  value: string;
303	  onChange: (next: string) => void;
304	  onBlur?: () => void;
305	  autoCapitalize?: TextInputProps['autoCapitalize'];
306	  autoCorrect?: boolean;
307	  autoComplete?: TextInputProps['autoComplete'];
308	  keyboardType?: TextInputProps['keyboardType'];
309	  placeholder?: string;
310	  error?: string;
311	  mono?: boolean;
312	  testID?: string;
313	};
