316	  label,
317	  value,
318	  onChange,
319	  onBlur,
320	  autoCapitalize,
321	  autoCorrect,
322	  autoComplete,
323	  keyboardType,
324	  placeholder,
325	  error,
326	  mono,
327	  testID,
328	}: FieldProps) {
329	  const hasError = !!error;
330	  return (
331	    <View style={styles.field}>
332	      <Text style={[textStyles.caption, styles.label]}>{label}</Text>
333	      <View style={[styles.inputWrap, shadows.hard, hasError && styles.inputWrapError]}>
334	        <TextInput
335	          value={value}
336	          onChangeText={onChange}
337	          onBlur={onBlur}
338	          autoCapitalize={autoCapitalize}
339	          autoCorrect={autoCorrect}
340	          autoComplete={autoComplete}
341	          keyboardType={keyboardType}
342	          placeholder={placeholder}
343	          placeholderTextColor={colors.ink40}
344	          style={[
345	            mono ? styles.inputMono : textStyles.body,
346	            styles.input,
347	          ]}
348	          accessibilityLabel={label}
349	          testID={testID}
350	        />
351	      </View>
352	      <Text
353	        style={[textStyles.caption, styles.errorText, !hasError && styles.errorHidden]}
354	        accessibilityLiveRegion="polite"
355	        importantForAccessibility={hasError ? 'yes' : 'no-hide-descendants'}
356	      >
357	        {error ?? ''}
358	      </Text>
359	    </View>
360	  );
361	}
